// ❌ BAD - direct DOM manipulation, bypasses React's diffing
function updateProductPrice(price) {
  document.getElementById('price').textContent = '$' + price;
}

// ✅ GOOD - React diffs and updates only what changed
function ProductPrice({ price }) {
  return <span className="price">${price}</span>;
}

// ❌ BAD - index as key causes wrong node reuse when list order changes
orders.map((order, index) => (
  <OrderRow key={index} order={order} />
));

// ✅ GOOD - stable unique ID lets React track items correctly
orders.map((order) => (
  <OrderRow key={order.id} order={order} />
));

// ❌ BAD - sorts the full customer list on every render, even unrelated state changes
function CustomerReport({ customers, searchTerm }) {
  const sorted = customers.slice().sort((a, b) => a.name.localeCompare(b.name));
  return <CustomerList items={sorted} />;
}

// ✅ GOOD - sort only runs when the customers array actually changes
function CustomerReport({ customers, searchTerm }) {
  const sorted = useMemo(
    () => customers.slice().sort((a, b) => a.name.localeCompare(b.name)),
    [customers]
  );
  return <CustomerList items={sorted} />;
}

// ❌ BAD - using state to store a timer ID causes an unnecessary re-render on each start/stop
const [timerId, setTimerId] = useState(null);
const start = () => setTimerId(setInterval(pollOrder, 2000));
const stop = () => { clearInterval(timerId); setTimerId(null); };

// ✅ GOOD - ref stores the timer ID without triggering any re-render
const timerRef = useRef(null);
const start = () => { timerRef.current = setInterval(pollOrder, 2000); };
const stop = () => { clearInterval(timerRef.current); };

// ❌ BAD - using useRef for derived data means it never updates automatically
const filteredRef = useRef(products.filter(p => p.inStock));
// filteredRef.current is stale when products changes

// ✅ GOOD - useMemo recomputes when products changes, useRef stores the abort controller
const inStockProducts = useMemo(
  () => products.filter(p => p.inStock),
  [products]
);
const abortRef = useRef(null); // manually set when starting a fetch

// ❌ BAD - threading auth user as a prop through every layout layer
function App() {
  const user = useAuth();
  return <Layout user={user}><Dashboard user={user} /></Layout>;
}

// ✅ GOOD - Context broadcasts the user without threading it as a prop
const AuthContext = createContext(null);
function App() {
  const user = useAuth();
  return (
    <AuthContext.Provider value={user}>
      <Layout><Dashboard /></Layout>
    </AuthContext.Provider>
  );
}
function Dashboard() {
  const user = useContext(AuthContext);
}

// ❌ BAD - sibling components each manage their own copy of the selected order
function OrderList() { const [selected, setSelected] = useState(null); }
function OrderDetail() { const [selected, setSelected] = useState(null); }

// ✅ GOOD - lift state to the parent so both siblings share the same value
function OrderPage() {
  const [selectedOrderId, setSelectedOrderId] = useState(null);
  return (
    <>
      <OrderList onSelect={setSelectedOrderId} />
      <OrderDetail orderId={selectedOrderId} />
    </>
  );
}

// ❌ BAD - JIT: shipping uncompiled Angular templates (requires runtime compiler in bundle)
// platformBrowserDynamic().bootstrapModule(AppModule) - this triggers JIT compilation

// ✅ GOOD - AOT: templates compiled before shipping (Angular production default)
// ng build --configuration production uses Ivy AOT compiler
// React equivalent: JSX is always transpiled at build time
const ProductCard = ({ name, price }) => (
  <div className="card"><h2>{name}</h2><span>${price}</span></div>
);

// ❌ BAD - mutating a React-managed node directly desyncs React's internal model
function PaymentForm() {
  const handleError = () => {
    document.getElementById('card-number').style.border = '2px solid red';
  };
}

// ✅ GOOD - use ref for imperative DOM access, let React handle everything else
function PaymentForm() {
  const cardInputRef = useRef(null);
  const handleError = () => {
    cardInputRef.current.focus();
  };
  return <input ref={cardInputRef} id="card-number" />;
}
